<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class AssetHistoryController{
 public function index():void{Auth::requireRole('owner','administrator','office','crew_leader');$pdo=Database::connection();$rows=$pdo->query("SELECT a.*,u.name performed_name,CASE WHEN a.asset_type='vehicle' THEN CONCAT(v.unit_number,' - ',v.name) ELSE i.name END asset_name FROM asset_activity a LEFT JOIN users u ON u.id=a.performed_by LEFT JOIN vehicles v ON a.asset_type='vehicle' AND v.id=a.asset_id LEFT JOIN inventory_items i ON a.asset_type='inventory' AND i.id=a.asset_id ORDER BY a.occurred_at DESC LIMIT 500")->fetchAll();$assets=$pdo->query("SELECT 'vehicle' asset_type,id,CONCAT(unit_number,' - ',name) asset_name FROM vehicles UNION ALL SELECT 'inventory',id,name FROM inventory_items ORDER BY asset_name")->fetchAll();View::render('portal/asset-history/index',['title'=>'Asset History','activities'=>$rows,'assets'=>$assets],'portal');}
 public function store():void{Auth::requireRole('owner','administrator','office','crew_leader');verify_csrf();Database::connection()->prepare('INSERT INTO asset_activity(asset_type,asset_id,activity_type,summary,details_json,performed_by,occurred_at) VALUES(?,?,?,?,?,?,?)')->execute([$_POST['asset_type'],(int)$_POST['asset_id'],trim($_POST['activity_type']),trim($_POST['summary']),json_encode(['notes'=>trim($_POST['notes']??'')]),Auth::id(),($_POST['occurred_at']??'')?:date('Y-m-d H:i:s')]);AuditService::log('asset.activity_added',$_POST['asset_type'],(int)$_POST['asset_id']);redirect('/portal/asset-history');}
}
